package main

import "fmt"

type Node struct {
	info rune
	next *Node
	prev *Node
}

type Editor struct {
	head *Node
	cursor *Node
}

func NewEditor() *Editor {
	sentinela := &Node{}
	sentinela.next = sentinela	
	sentinela.prev = sentinela
	return &Editor{head: sentinela, cursor: sentinela}
}

func (edt *Editor) BackSpace(ref *Node) {

	target := edt.cursor.prev

	target.prev.next = target.next
	target.next.prev = target.prev

}

func main(){

    editor := NewEditor()

	var word string

	fmt.Scan(&word)

    for _, elem := range word {
        if elem == '|' {
            editor.BackSpace(editor.cursor)
        }
    }

}
